$ErrorActionPreference = "Stop"

# Arc Browser のパスをレジストリから取得
$arcPath = (Get-ItemProperty "HKCU:\Software\Microsoft\Windows\CurrentVersion\App Paths\Arc.exe" -ErrorAction SilentlyContinue).'(default)'

if (-not $arcPath -or -not (Test-Path $arcPath)) {
    Write-Host "Arc Browser が見つかりません。既定ブラウザで開きます。"
    $arcPath = $null
}

function Open-Url($url) {
    if ($arcPath) {
        Start-Process $arcPath $url
    } else {
        Start-Process $url
    }
}

