    "https://sgsv1.tokyo.meidensha.co.jp/SmartGrasper/joblist"
)

foreach ($url in $urls_before) { Open-Url $url }

Write-Host ""
Write-Host "--------------------------------------------------"
Write-Host "Please login at meiden.cybozu.com"
Write-Host "--------------------------------------------------"
Read-Host | Out-Null

foreach ($url in $urls_after) { Open-Url $url }

Write-Host ""
Write-Host "Done."

