cat << 'PS1' > /tmp/check_arc.ps1
# Check Arc window titles
$procs = Get-Process Arc -ErrorAction SilentlyContinue | Where-Object { $_.MainWindowTitle -ne "" }
if ($procs) {
    Write-Host "=== Arc Windows ==="
    $procs | ForEach-Object { Write-Host "  PID $($_.Id): $($_.MainWindowTitle)" }
} else {
    Write-Host "No Arc windows with titles found"
}

# Screenshot capability
Write-Host ""
Write-Host "=== Screenshot Test ==="
try {
    Add-Type -AssemblyName System.Windows.Forms
    Add-Type -AssemblyName System.Drawing
    $screen = [System.Windows.Forms.Screen]::PrimaryScreen.Bounds
    $bmp = New-Object System.Drawing.Bitmap($screen.Width, $screen.Height)
    $g = [System.Drawing.Graphics]::FromImage($bmp)
    $g.CopyFromScreen($screen.Location, [System.Drawing.Point]::Empty, $screen.Size)
    $path = "$env:TEMP\screenshot_test.png"
    $bmp.Save($path)
    $g.Dispose()
    $bmp.Dispose()
    Write-Host "Screenshot saved: $path"
    Write-Host "Size: $((Get-Item $path).Length) bytes"
} catch {
    Write-Host "Screenshot failed: $_"
}
PS1
powershell -ExecutionPolicy Bypass -File "$(cygpath -w /tmp/check_arc.ps1)"

