cat << 'PS1' > /tmp/verify_urls2.ps1
# Bring Arc to foreground
Add-Type @"
using System;
using System.Runtime.InteropServices;
public class Win32 {
    [DllImport("user32.dll")] public static extern bool SetForegroundWindow(IntPtr hWnd);
    [DllImport("user32.dll")] public static extern bool ShowWindow(IntPtr hWnd, int nCmdShow);
}
"@

$arc = Get-Process Arc -ErrorAction SilentlyContinue | Where-Object { $_.MainWindowHandle -ne 0 } | Select-Object -First 1
if ($arc) {
    [Win32]::ShowWindow($arc.MainWindowHandle, 9)  # SW_RESTORE
    [Win32]::SetForegroundWindow($arc.MainWindowHandle)
    Write-Host "Brought Arc to foreground (PID $($arc.Id))"
} else {
    Write-Host "No Arc window found"
}

Start-Sleep -Seconds 2

# Screenshot
Add-Type -AssemblyName System.Windows.Forms, System.Drawing
$s = [System.Windows.Forms.Screen]::PrimaryScreen.Bounds
$bmp = New-Object System.Drawing.Bitmap($s.Width, $s.Height)
$g = [System.Drawing.Graphics]::FromImage($bmp)
$g.CopyFromScreen($s.Location, [System.Drawing.Point]::Empty, $s.Size)
$path = "$env:TEMP\verify_arc.png"
$bmp.Save($path)
$g.Dispose(); $bmp.Dispose()
Write-Host "Screenshot: $path"
PS1
powershell -ExecutionPolicy Bypass -File "$(cygpath -w /tmp/verify_urls2.ps1)"
